#!/usr/bin/env python3
"""Apply risk engine to merged signals and emit approved signals + proposed orders."""

from __future__ import annotations

import argparse
import json
import sys
from datetime import datetime
from pathlib import Path
from typing import Any

import pandas as pd

PROJECT_ROOT = Path(__file__).resolve().parents[1]
if str(PROJECT_ROOT) not in sys.path:
    sys.path.insert(0, str(PROJECT_ROOT))

from risk.exit_engine import generate_exit_signals, normalize_ts_code
from risk.risk_engine import RiskConfig, RiskContext, RiskEngine
from scripts.signal_schema import validate_signal_frame
from scripts.runtime_date_utils import (
    load_dated_live_system_payload,
    load_index_return_pct_for_date,
    load_market_breadth_ratio_for_date,
    load_style_rotation_snapshot_for_date,
    parse_date_tag,
    resolve_benchmark_code,
)

SELL_SIGNAL_TYPES = {"SELL", "REDUCE", "EXIT", "CLOSE"}
BUY_SIGNAL_TYPES = {"BUY", "ADD", "OPEN"}
DEFAULT_LIVE_CONFIG_PATH = PROJECT_ROOT / "config" / "live_trading_v1.json"


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def load_json(path: Path | None) -> dict[str, Any]:
    if path is None or not path.exists():
        return {}
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def build_risk_config(risk_payload: dict[str, Any], live_config: dict[str, Any] | None = None) -> RiskConfig:
    live_risk_cfg = ((live_config or {}).get("risk", {}) or {}) if isinstance(live_config, dict) else {}
    live_style_cfg = {}
    if isinstance(live_risk_cfg.get("style_rotation"), dict):
        live_style_cfg = live_risk_cfg.get("style_rotation") or {}
    elif isinstance((live_config or {}).get("style_rotation"), dict):
        live_style_cfg = (live_config or {}).get("style_rotation") or {}

    def choose(key: str, default: Any = None) -> Any:
        if key in risk_payload:
            return risk_payload.get(key)
        if key in live_risk_cfg:
            value = live_risk_cfg.get(key)
            if value is not None:
                return value
        return default

    def choose_style(key: str, default: Any = None) -> Any:
        style_payload = risk_payload.get("style_rotation") or {}
        if isinstance(style_payload, dict) and key in style_payload:
            return style_payload.get(key)
        if key in live_style_cfg:
            value = live_style_cfg.get(key)
            if value is not None:
                return value
        return default

    if risk_payload:
        return RiskConfig(
            max_total_exposure=choose("max_total_exposure", 1.0),
            max_single_weight=choose("max_single_weight", 0.10),
            riskoff_total_exposure=choose("riskoff_total_exposure", 0.65),
            hard_stop_enabled=choose("hard_stop_enabled", True),
            allow_new_buy_when_riskoff=choose("allow_new_buy_when_riskoff", False),
            max_order_to_adv20_ratio=choose("max_order_to_adv20_ratio", 0.02),
            index_halt_threshold_pct=choose("index_halt_threshold_pct"),
            market_breadth_riskoff_threshold=choose("market_breadth_riskoff_threshold"),
            market_breadth_hard_stop_threshold=choose("market_breadth_hard_stop_threshold"),
            strategy_max_drawdown_riskoff_pct=choose("strategy_max_drawdown_riskoff_pct"),
            strategy_sharpe_cautious_threshold=choose("strategy_sharpe_cautious_threshold"),
            blocked_codes=choose("blocked_codes", []),
            style_rotation_enabled=bool(choose_style("enabled", False)),
            style_rotation_riskoff_short_excess_pct=choose_style("riskoff_short_excess_pct"),
            style_rotation_riskoff_medium_excess_pct=choose_style("riskoff_medium_excess_pct"),
            style_rotation_hard_stop_short_excess_pct=choose_style("hard_stop_short_excess_pct"),
            style_rotation_hard_stop_medium_excess_pct=choose_style("hard_stop_medium_excess_pct"),
            style_rotation_hard_stop_requires_negative_smallcap=bool(
                choose_style("hard_stop_requires_negative_smallcap", True)
            ),
        )
    return RiskConfig(
        max_total_exposure=parse_float(live_risk_cfg.get("max_total_exposure"), 1.0),
        max_single_weight=parse_float(live_risk_cfg.get("max_single_weight"), 0.10),
        riskoff_total_exposure=parse_float(live_risk_cfg.get("riskoff_total_exposure"), 0.65),
        allow_new_buy_when_riskoff=bool(live_risk_cfg.get("allow_new_buy_when_riskoff", False)),
        index_halt_threshold_pct=live_risk_cfg.get("index_halt_threshold_pct"),
        market_breadth_riskoff_threshold=live_risk_cfg.get("market_breadth_riskoff_threshold"),
        market_breadth_hard_stop_threshold=live_risk_cfg.get("market_breadth_hard_stop_threshold"),
        strategy_max_drawdown_riskoff_pct=live_risk_cfg.get("strategy_max_drawdown_riskoff_pct"),
        strategy_sharpe_cautious_threshold=live_risk_cfg.get("strategy_sharpe_cautious_threshold"),
        style_rotation_enabled=bool(choose_style("enabled", False)),
        style_rotation_riskoff_short_excess_pct=choose_style("riskoff_short_excess_pct"),
        style_rotation_riskoff_medium_excess_pct=choose_style("riskoff_medium_excess_pct"),
        style_rotation_hard_stop_short_excess_pct=choose_style("hard_stop_short_excess_pct"),
        style_rotation_hard_stop_medium_excess_pct=choose_style("hard_stop_medium_excess_pct"),
        style_rotation_hard_stop_requires_negative_smallcap=bool(
            choose_style("hard_stop_requires_negative_smallcap", True)
        ),
    )


def merge_exit_signals(approved: pd.DataFrame, exit_signals: pd.DataFrame) -> pd.DataFrame:
    if approved is None or approved.empty:
        base = pd.DataFrame()
    else:
        base = approved.copy()
    if exit_signals is None or exit_signals.empty:
        return base

    exit_signals = exit_signals.copy()
    exit_codes = {
        normalize_ts_code(code)
        for code in exit_signals["ts_code"].fillna("").astype(str).tolist()
        if normalize_ts_code(code)
    }
    if not base.empty and "signal_type" in base.columns and "ts_code" in base.columns:
        signal_series = base["signal_type"].fillna("").astype(str).str.upper().str.strip()
        code_series = base["ts_code"].map(normalize_ts_code)
        existing_sell_codes = set(code_series[signal_series.isin(SELL_SIGNAL_TYPES)].tolist())
        exit_signals = exit_signals[
            ~exit_signals["ts_code"].map(normalize_ts_code).isin(existing_sell_codes)
        ].copy()
        all_sell_codes = existing_sell_codes | exit_codes
        buy_mask = signal_series.isin(BUY_SIGNAL_TYPES) & code_series.isin(all_sell_codes)
        if bool(buy_mask.any()):
            base = base.loc[~buy_mask].copy()

    if exit_signals.empty:
        return base

    combined = pd.concat([base, exit_signals], ignore_index=True, sort=False)
    if {"trade_date", "ts_code", "signal_type"}.issubset(combined.columns):
        if "score" not in combined.columns:
            combined["score"] = 0.0
        combined["ts_code"] = combined["ts_code"].map(normalize_ts_code)
        combined["signal_type"] = combined["signal_type"].fillna("").astype(str).str.upper().str.strip()
        combined = combined.sort_values(["trade_date", "ts_code", "signal_type", "score"], ascending=[True, True, True, False])
        combined = combined.drop_duplicates(subset=["trade_date", "ts_code", "signal_type"], keep="first")
    return combined.reset_index(drop=True)


def build_orders_frame(approved: pd.DataFrame, *, account_nav: float, available_cash: float, input_path: Path) -> pd.DataFrame:
    keep_cols = [
        "trade_date",
        "ts_code",
        "action",
        "target_value",
        "target_weight",
        "target_qty",
        "ref_price",
        "strategy_id",
        "score",
        "risk_adjustment",
        "risk_status",
        "exit_type",
        "exit_reason",
        "reduce_score",
        "reduce_rank_reason",
        "reason",
        "source_signal_file",
        "generated_at",
        "approved",
    ]
    if approved is None or approved.empty:
        return pd.DataFrame(columns=keep_cols)

    orders = approved[approved["approved"].fillna(False)].copy() if "approved" in approved.columns else approved.copy()
    if orders.empty:
        return pd.DataFrame(columns=keep_cols)

    orders["signal_type"] = orders["signal_type"].fillna("").astype(str).str.upper().str.strip()
    buy_mask = orders["signal_type"].isin(BUY_SIGNAL_TYPES)
    sell_mask = orders["signal_type"].isin(SELL_SIGNAL_TYPES)

    orders["target_value"] = 0.0
    if "target_weight" in orders.columns:
        orders["target_weight"] = pd.to_numeric(orders["target_weight"], errors="coerce")
        orders.loc[buy_mask, "target_value"] = orders.loc[buy_mask, "target_weight"].fillna(0.0) * account_nav
    else:
        buy_rows = max(1, int(orders.loc[buy_mask, "ts_code"].nunique() or 1))
        default_value = available_cash / buy_rows
        orders.loc[buy_mask, "target_value"] = default_value

    if "target_qty" not in orders.columns:
        orders["target_qty"] = None
    if "ref_price" not in orders.columns:
        orders["ref_price"] = None

    qty_series = pd.to_numeric(orders["target_qty"], errors="coerce").fillna(0.0)
    price_series = pd.to_numeric(orders["ref_price"], errors="coerce").fillna(0.0)
    sell_value_mask = sell_mask & (qty_series > 0) & (price_series > 0)
    orders.loc[sell_value_mask, "target_value"] = qty_series[sell_value_mask] * price_series[sell_value_mask]

    orders["action"] = orders["signal_type"]
    if "reason" not in orders.columns:
        orders["reason"] = orders.get("comment", "")
    else:
        comment_series = orders.get("comment", "")
        orders["reason"] = orders["reason"].fillna("").astype(str)
        orders.loc[orders["reason"].str.strip() == "", "reason"] = comment_series
    if "exit_reason" not in orders.columns:
        orders["exit_reason"] = None
    if "exit_type" not in orders.columns:
        orders["exit_type"] = None
    orders["generated_at"] = datetime.now().astimezone().isoformat()
    orders["source_signal_file"] = str(input_path)

    for col in keep_cols:
        if col not in orders.columns:
            orders[col] = None
    return orders[keep_cols].reset_index(drop=True)


def enrich_runtime_inputs(
    *,
    trade_date: str,
    live_config: dict[str, Any],
    market_breadth: float | None,
    index_ret_pct: float | None,
    strategy_max_dd_pct: float | None,
    strategy_sharpe: float | None,
) -> dict[str, Any]:
    date_tag = parse_date_tag(trade_date)
    style_snapshot = load_style_rotation_snapshot_for_date(live_config, date_tag)
    payload = {
        "market_breadth": market_breadth,
        "index_ret_pct": index_ret_pct,
        "strategy_max_dd_pct": strategy_max_dd_pct,
        "strategy_sharpe": strategy_sharpe,
        "style_snapshot": style_snapshot,
        "source": "cli",
    }
    if not isinstance(live_config, dict) or not live_config:
        return payload
    if all(value is not None for value in [market_breadth, index_ret_pct, strategy_max_dd_pct, strategy_sharpe]):
        return payload

    derived_market_breadth = market_breadth
    if derived_market_breadth is None:
        derived_market_breadth = load_market_breadth_ratio_for_date(date_tag)

    if index_ret_pct is None:
        index_ret_pct = load_index_return_pct_for_date(date_tag, resolve_benchmark_code(live_config))

    live_system_path = None
    combo: dict[str, Any] = {}
    if strategy_max_dd_pct is None:
        live_system_path, live_payload = load_dated_live_system_payload(date_tag)
        combo = live_payload.get("combo_v1", {}) or {}
        strategy_max_dd_pct = parse_float(combo.get("max_drawdown_pct"), 0.0)
    if strategy_sharpe is None:
        if not combo:
            live_system_path, live_payload = load_dated_live_system_payload(date_tag)
            combo = live_payload.get("combo_v1", {}) or {}
        strategy_sharpe = parse_float(combo.get("sharpe"), 0.0)

    payload.update(
        {
            "market_breadth": derived_market_breadth,
            "index_ret_pct": index_ret_pct,
            "strategy_max_dd_pct": strategy_max_dd_pct,
            "strategy_sharpe": strategy_sharpe,
            "style_snapshot": style_snapshot,
            "source": str(live_system_path) if live_system_path is not None else f"dated_runtime:{date_tag}",
        }
    )
    return payload


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("--input", required=True, help="merged signal csv")
    ap.add_argument("--trade-date", required=True)
    ap.add_argument("--account-nav", type=float, default=1000000)
    ap.add_argument("--available-cash", type=float, default=1000000)
    ap.add_argument("--market-breadth", type=float, default=None)
    ap.add_argument("--index-ret-pct", type=float, default=None)
    ap.add_argument("--strategy-max-dd-pct", type=float, default=None)
    ap.add_argument("--strategy-sharpe", type=float, default=None)
    ap.add_argument("--risk-off", action="store_true")
    ap.add_argument("--hard-stop", action="store_true")
    ap.add_argument("--risk-config", type=str, default=None, help="path to risk config JSON")
    ap.add_argument("--live-config", type=str, default=str(DEFAULT_LIVE_CONFIG_PATH), help="path to live config JSON")
    ap.add_argument("--holdings", type=str, default="", help="optional holdings csv for exit engine")
    ap.add_argument("--trade-history", type=str, default="", help="optional trade history csv for exit engine")
    ap.add_argument("--approved-output", type=str, default="", help="optional approved signals output csv")
    ap.add_argument("--orders-output", type=str, default="", help="optional proposed orders output csv")
    args = ap.parse_args()

    input_path = Path(args.input)
    if not input_path.exists():
        raise FileNotFoundError(input_path)

    merged = validate_signal_frame(
        pd.read_csv(input_path),
        context=f"apply_risk_to_merged_signals:{input_path.name}",
    )
    live_config_path = Path(args.live_config).expanduser().resolve() if args.live_config else None
    live_config = load_json(live_config_path)
    risk_payload = load_json(Path(args.risk_config).expanduser().resolve()) if args.risk_config else {}
    runtime_inputs = enrich_runtime_inputs(
        trade_date=args.trade_date,
        live_config=live_config,
        market_breadth=args.market_breadth,
        index_ret_pct=args.index_ret_pct,
        strategy_max_dd_pct=args.strategy_max_dd_pct,
        strategy_sharpe=args.strategy_sharpe,
    )

    engine = RiskEngine(build_risk_config(risk_payload, live_config=live_config))
    context = RiskContext(
        trade_date=args.trade_date,
        market_breadth=runtime_inputs["market_breadth"],
        risk_off=args.risk_off,
        hard_stop=args.hard_stop,
        available_cash=args.available_cash,
        account_nav=args.account_nav,
        index_ret_pct=runtime_inputs["index_ret_pct"],
        strategy_max_drawdown_pct=runtime_inputs["strategy_max_dd_pct"],
        strategy_sharpe=runtime_inputs["strategy_sharpe"],
        style_smallcap_short_return_pct=parse_float(
            (runtime_inputs.get("style_snapshot") or {}).get("smallcap_short_return_pct"),
            0.0,
        ) if (runtime_inputs.get("style_snapshot") or {}).get("smallcap_short_return_pct") is not None else None,
        style_smallcap_medium_return_pct=parse_float(
            (runtime_inputs.get("style_snapshot") or {}).get("smallcap_medium_return_pct"),
            0.0,
        ) if (runtime_inputs.get("style_snapshot") or {}).get("smallcap_medium_return_pct") is not None else None,
        style_short_excess_pct=parse_float(
            (runtime_inputs.get("style_snapshot") or {}).get("short_excess_pct"),
            0.0,
        ) if (runtime_inputs.get("style_snapshot") or {}).get("short_excess_pct") is not None else None,
        style_medium_excess_pct=parse_float(
            (runtime_inputs.get("style_snapshot") or {}).get("medium_excess_pct"),
            0.0,
        ) if (runtime_inputs.get("style_snapshot") or {}).get("medium_excess_pct") is not None else None,
    )

    approved = engine.apply(merged, context)
    runtime_decision = engine.evaluate_runtime_state(context)

    merged_signal_type = merged.get("signal_type", pd.Series(dtype=str)).fillna("").astype(str).str.upper().str.strip()
    buy_frame = merged.loc[merged_signal_type.isin(BUY_SIGNAL_TYPES)].copy() if not merged.empty else pd.DataFrame()
    candidate_codes = {
        normalize_ts_code(code)
        for code in buy_frame.get("ts_code", pd.Series(dtype=str)).tolist()
        if normalize_ts_code(code)
    }
    buy_score_map = {}
    if not buy_frame.empty and "score" in buy_frame.columns:
        buy_score_map = {
            normalize_ts_code(row.ts_code): parse_float(row.score, 0.0)
            for row in buy_frame[["ts_code", "score"]].itertuples(index=False)
            if normalize_ts_code(row.ts_code)
        }

    execution_cfg = (live_config.get("execution", {}) or {}) if isinstance(live_config, dict) else {}
    lot_size = max(1, int(parse_float(execution_cfg.get("lot_size"), 100)))
    holdings_path = Path(args.holdings).expanduser().resolve() if args.holdings else None
    trade_history_path = Path(args.trade_history).expanduser().resolve() if args.trade_history else None
    exit_signals, exit_summary = generate_exit_signals(
        trade_date=args.trade_date,
        account_nav=args.account_nav,
        mode=runtime_decision.mode,
        live_config=live_config,
        project_root=PROJECT_ROOT,
        report_dir=PROJECT_ROOT / "research" / "reports",
        holdings_path=holdings_path,
        trade_history_path=trade_history_path,
        lot_size=lot_size,
        candidate_codes=candidate_codes,
        buy_score_map=buy_score_map,
    )

    combined_approved = validate_signal_frame(
        merge_exit_signals(approved, exit_signals),
        context="apply_risk_to_merged_signals:combined_approved",
    )

    trade_tag = args.trade_date.replace("-", "")
    approved_path = (
        Path(args.approved_output).expanduser().resolve()
        if args.approved_output
        else PROJECT_ROOT / "signals" / "approved" / f"merged_approved_signals_{trade_tag}.csv"
    )
    approved_path.parent.mkdir(parents=True, exist_ok=True)
    combined_approved.to_csv(approved_path, index=False)

    orders = build_orders_frame(
        combined_approved,
        account_nav=args.account_nav,
        available_cash=args.available_cash,
        input_path=input_path,
    )
    proposed_path = (
        Path(args.orders_output).expanduser().resolve()
        if args.orders_output
        else PROJECT_ROOT / "orders" / "proposed" / f"merged_proposed_orders_{trade_tag}.csv"
    )
    proposed_path.parent.mkdir(parents=True, exist_ok=True)
    orders.to_csv(proposed_path, index=False)

    print(f"merged approved signals -> {approved_path}")
    print(f"merged proposed orders -> {proposed_path}")
    approved_true = int(combined_approved["approved"].fillna(False).sum()) if "approved" in combined_approved.columns else len(combined_approved)
    print(f"rows: total={len(combined_approved)}, approved={approved_true}, orders={len(orders)}")
    print(
        "exit_engine: "
        f"rows={exit_summary.get('exit_rows', 0)} "
        f"stop_loss={exit_summary.get('stop_loss_count', 0)} "
        f"(reduce={exit_summary.get('stop_loss_reduce_count', 0)} hard={exit_summary.get('stop_loss_hard_count', 0)}) "
        f"trailing={exit_summary.get('trailing_stop_count', 0)} "
        f"de_risk={exit_summary.get('de_risk_count', 0)} "
        f"mode={exit_summary.get('mode', runtime_decision.mode)} "
        f"holdings={exit_summary.get('holdings_path', '') or '-'} "
        f"runtime_source={runtime_inputs.get('source', '-')}"
    )


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import math
import subprocess
import sys
from datetime import datetime
from pathlib import Path
from typing import Any

