def validate_materialize_ops(ops: list[dict[str, Any]], *, date_tag: str) -> None:
    failed = [op for op in ops if int(op.get("returncode", 0)) != 0]
    if failed:
        details = [
            {
                "step": op.get("step", ""),
                "returncode": op.get("returncode", ""),
                "stderr": op.get("stderr", ""),
                "stdout": op.get("stdout", ""),
            }
            for op in failed
        ]
        raise RuntimeError(
            json.dumps(
                {
                    "date_tag": date_tag,
                    "reason": "materialize_signal_chain_failed",
                    "failed_ops": details,
                },
                ensure_ascii=False,
            )
        )


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        parsed = float(str(value).replace(",", "").strip())
        return parsed if math.isfinite(parsed) else default
    except Exception:
        return default


def parse_int(value: Any, default: int = 0) -> int:
    try:
        return int(float(str(value).replace(",", "").strip()))
    except Exception:
        return default


def parse_bool(value: Any, default: bool = False) -> bool:
    if value is None:
        return default
    text = str(value).strip().lower()
    if text in {"1", "true", "yes", "y", "ok"}:
        return True
    if text in {"0", "false", "no", "n"}:
        return False
    return default


def normalize_side(value: Any) -> str:
    text = str(value or "").strip().upper()
    if text in {"BUY", "SELL"}:
        return text
    if any(k in text for k in ["买", "BUY", "B", "LONG"]):
        return "BUY"
    if any(k in text for k in ["卖", "SELL", "S", "SHORT"]):
        return "SELL"
    return ""


def normalize_joinquant_code(value: Any) -> str:
    raw = str(value or "").strip().upper()
    if not raw or raw == "NAN":
        return ""
    if raw.endswith(".XSHG") or raw.endswith(".XSHE"):
        return raw
    if raw.endswith(".SH"):
        return raw[:-3] + ".XSHG"
    if raw.endswith(".SZ"):
        return raw[:-3] + ".XSHE"
    if raw.startswith("SH") and len(raw) >= 8:
        return f"{raw[2:8]}.XSHG"
    if raw.startswith("SZ") and len(raw) >= 8:
        return f"{raw[2:8]}.XSHE"
    if raw.isdigit() and len(raw) == 6:
        market = "XSHG" if raw.startswith(("5", "6", "9")) else "XSHE"
        return f"{raw}.{market}"
    return raw


def to_tushare_code(joinquant_code: str) -> str:
    code = normalize_joinquant_code(joinquant_code)
    if "." not in code:
        return ""
    symbol, market = code.split(".", 1)
    if market == "XSHG":
        return f"{symbol}.SH"
    if market == "XSHE":
        return f"{symbol}.SZ"
    return ""


def count_csv_rows(path: Path) -> int:
    if not path.exists():
        return 0
    try:
        with path.open("r", encoding="utf-8", newline="") as handle:
            return max(0, sum(1 for _ in handle) - 1)
    except Exception:
        return 0


def latest_file_by_pattern(pattern: str) -> Path | None:
    files = sorted(REPORT_DIR.glob(pattern), key=lambda p: p.stat().st_mtime, reverse=True)
    return files[0] if files else None


