def resolve_holdings_path(date_tag: str) -> Path | None:
    normalized = str(date_tag or "").strip()
    exact_candidates = [
        REPORT_DIR / f"ths_selected_holdings_{normalized}.csv",
        REPORT_DIR / f"account_holdings_selected_{normalized}.csv",
        REPORT_DIR / "ths_selected_holdings_latest.csv",
        REPORT_DIR / "account_holdings_selected_latest.csv",
    ]
    for path in exact_candidates:
        if path.exists():
            return path

    fallback_patterns = [
        "ths_selected_holdings_*.csv",
        "account_holdings_selected_*.csv",
    ]
    for pattern in fallback_patterns:
        match = latest_file_by_pattern(pattern)
        if match is not None:
            return match
    return None


def summarize_signal_chain_truth(date_tag: str) -> dict[str, Any]:
    merged_path = SIGNALS_MERGED_DIR / f"merged_signals_{date_tag}.csv"
    approved_path = SIGNALS_APPROVED_DIR / f"merged_approved_signals_{date_tag}.csv"
    proposed_path = ORDERS_DIR / f"merged_proposed_orders_{date_tag}.csv"

    def count_by_side(path: Path, column: str, values: set[str], *, require_approved: bool = False) -> int:
        if not path.exists():
            return 0
        try:
            frame = pd.read_csv(path)
        except Exception:
            return 0
        if frame.empty or column not in frame.columns:
            return 0
        if require_approved and "approved" in frame.columns:
            approved_series = frame["approved"].map(lambda x: parse_bool(x, False))
            frame = frame.loc[approved_series].copy()
            if frame.empty:
                return 0
        side_series = frame[column].fillna("").astype(str).str.upper().str.strip()
        return int(side_series.isin(values).sum())

    merged_buy_rows = count_by_side(merged_path, "signal_type", {"BUY", "ADD", "OPEN"})
    merged_sell_rows = count_by_side(merged_path, "signal_type", {"SELL", "REDUCE", "EXIT", "CLOSE"})
    approved_buy_rows = count_by_side(approved_path, "signal_type", {"BUY", "ADD", "OPEN"}, require_approved=True)
    approved_sell_rows = count_by_side(approved_path, "signal_type", {"SELL", "REDUCE", "EXIT", "CLOSE"}, require_approved=True)
    proposed_buy_rows = count_by_side(proposed_path, "action", {"BUY", "ADD", "OPEN"})
    proposed_sell_rows = count_by_side(proposed_path, "action", {"SELL", "REDUCE", "EXIT", "CLOSE"})

    return {
        "merged_signals_file": str(merged_path) if merged_path.exists() else "",
        "approved_signals_file": str(approved_path) if approved_path.exists() else "",
        "proposed_orders_file": str(proposed_path) if proposed_path.exists() else "",
        "merged_buy_rows": merged_buy_rows,
        "merged_sell_rows": merged_sell_rows,
        "approved_buy_rows": approved_buy_rows,
        "approved_sell_rows": approved_sell_rows,
        "blocked_buy_rows": max(0, merged_buy_rows - approved_buy_rows),
        "proposed_buy_rows": proposed_buy_rows,
        "proposed_sell_rows": proposed_sell_rows,
        "buy_signal_visible": merged_buy_rows > 0,
        "buy_signal_ticketed": proposed_buy_rows > 0,
    }


