        if ai_realtime_change_pct and ai_realtime_change_pct.lower() != "nan":
            notes_bits.append(f"ai_realtime_change_pct={ai_realtime_change_pct}")
        ai_realtime_confirmed = str(raw.get("ai_realtime_confirmed") or "").strip()
        if ai_realtime_confirmed and ai_realtime_confirmed.lower() != "nan":
            notes_bits.append(f"ai_realtime_confirmed={ai_realtime_confirmed}")

        source_time = str(raw.get("generated_at") or raw.get("trade_date") or "").strip()
        if len(source_time) == 10 and source_time.count("-") == 2:
            source_time = f"{source_time} 09:25:00 +0800"

        signed_qty = hint_qty if side == "BUY" else -hint_qty
        source_amount = round((hint_qty * price) if price > 0 else abs(target_value), 2)
        rows.append(
            {
                "ticket_time": now_text,
                "ts_code": jq_code,
                "side": side,
                "source_time": source_time,
                "source_qty": signed_qty,
                "source_price": round(price, 4) if price > 0 else "",
                "source_amount": source_amount if source_amount > 0 else "",
                "reason": reason,
                "confirm_status": "pending_user_confirm",
                "execute_status": "not_sent",
                "notes": ";".join(notes_bits),
            }
        )

    stats = {
        "source_rows": int(len(frame)),
        "kept_rows": int(len(rows)),
        "dropped_no_code": dropped_no_code,
        "dropped_no_qty": dropped_no_qty,
    }
    return rows, stats


def main() -> None:
    parser = argparse.ArgumentParser(description="准备当日可消费的 live signal tickets")
    parser.add_argument("--date", default="", help="YYYYMMDD，默认今天")
    parser.add_argument("--available-cash", type=float, default=DEFAULT_AVAILABLE_CASH)
    parser.add_argument("--account-nav", type=float, default=DEFAULT_ACCOUNT_NAV)
    parser.add_argument("--lot-size", type=int, default=DEFAULT_LOT_SIZE)
    parser.add_argument("--force-rebuild", action="store_true", help="忽略现有当日产物并重建 tickets")
    args = parser.parse_args()

    date_tag = args.date.strip() or datetime.now().strftime("%Y%m%d")
    out_ticket = ticket_path(date_tag)
    out_summary = summary_path(date_tag)

    payload: dict[str, Any] = {
        "generated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "date_tag": date_tag,
        "pipeline_kind": "live",
        "generated_by": "prepare_live_signal_tickets.py",
        "ticket_file": str(out_ticket),
        "source_kind": "",
        "source_file": "",
        "status": "",
        "reason": "",
        "rows": 0,
        "materialize_ops": [],
        "stats": {},
        "signal_chain_truth": {},
    }

    existing_ticket = live_ticket_path(date_tag)
    if (not args.force_rebuild) and existing_ticket.exists() and count_csv_rows(existing_ticket) > 0:
        payload["status"] = "PASS"
        payload["reason"] = "existing_live_stock_signal_tickets"
        payload["source_kind"] = "existing_live_stock_signal_tickets"
        payload["source_file"] = str(existing_ticket)
        payload["rows"] = count_csv_rows(existing_ticket)
        write_summary(out_summary, payload)
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return

    legacy_ticket = legacy_ticket_path(date_tag)
    if (not args.force_rebuild) and legacy_ticket.exists() and count_csv_rows(legacy_ticket) > 0:
        payload["status"] = "PASS"
        payload["reason"] = "existing_legacy_stock_signal_tickets"
        payload["source_kind"] = "existing_legacy_stock_signal_tickets"
        payload["source_file"] = str(legacy_ticket)
        payload["rows"] = count_csv_rows(legacy_ticket)
        write_summary(out_summary, payload)
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return

    existing_joinquant = REPORT_DIR / f"joinquant_order_tickets_{date_tag}.csv"
    if (not args.force_rebuild) and existing_joinquant.exists() and count_csv_rows(existing_joinquant) > 0:
        ensure_parent(out_ticket)
        out_ticket.write_text(existing_joinquant.read_text(encoding="utf-8"), encoding="utf-8")
        payload["status"] = "PASS"
        payload["reason"] = "copied_existing_joinquant_ticket"
        payload["source_kind"] = "joinquant_order_tickets"
        payload["source_file"] = str(existing_joinquant)
        payload["rows"] = count_csv_rows(out_ticket)
        write_summary(out_summary, payload)
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return

    payload["materialize_ops"] = materialize_signal_chain(
        date_tag=date_tag,
        available_cash=float(args.available_cash),
        account_nav=float(args.account_nav),
        force_rebuild=bool(args.force_rebuild),
    )
    validate_materialize_ops(payload["materialize_ops"], date_tag=date_tag)

    source_kind, source_path = choose_source_file(date_tag)
    if source_path is None:
        write_ticket_rows(out_ticket, [])
        payload["status"] = "EMPTY"
        payload["reason"] = "no_same_day_signal_source"
        write_summary(out_summary, payload)
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return

    rows, stats = build_ticket_rows(
        source_kind=source_kind,
        source_path=source_path,
        date_tag=date_tag,
        account_nav=float(args.account_nav),
        lot_size=max(1, int(args.lot_size)),
    )
    write_ticket_rows(out_ticket, rows)

    payload["source_kind"] = source_kind
    payload["source_file"] = str(source_path)
    payload["rows"] = int(len(rows))
    payload["stats"] = stats
    payload["signal_chain_truth"] = summarize_signal_chain_truth(date_tag)
    payload["signal_chain_truth"]["ticket_buy_rows"] = sum(1 for row in rows if str(row.get("side") or "").upper() == "BUY")
    payload["signal_chain_truth"]["ticket_sell_rows"] = sum(1 for row in rows if str(row.get("side") or "").upper() == "SELL")
    if rows:
        payload["status"] = "PASS"
        payload["reason"] = "prepared_signal_tickets"
    else:
        payload["status"] = "EMPTY"
        payload["reason"] = "same_day_signal_source_has_no_effective_rows"

    write_summary(out_summary, payload)
    print(json.dumps(payload, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

